    private boolean isPropertiesListSizesEquals(final Collection<PropertyDefinition> pt1Props,
                                                final Collection<PropertyDefinition> pt2Props) {
        return (isEmpty(pt1Props) && isEmpty(pt2Props))
            || (isNotEmpty(pt1Props) && isNotEmpty(pt2Props) && pt1Props.size() == pt2Props.size());
